import react, { useeffect, usestate } from 'react';

function tablecomponent() {
  const records = [
    { id: 1, name: 'adam', age: 25 },
    { id: 2, name: 'james', age: 30 },
    { id: 3, name: 'nick', age: 28 },
    { id: 4, name: 'john', age: 29 }
  ];

  const [sorteddata, setsorteddata] = usestate(records);
  const [filterterm, setfilterterm] = usestate('');
  const [sortcolumn, setsortcolumn] = usestate(null);
  const [sortdirection, setsortdirection] = usestate('asc');

  const handlefilterchange = (e) => {
    setfilterterm(e.target.value.toLowerCase());
  };

  const handlesort = (column) => {
    if (sortcolumn === column) {
      setsortdirection(sortdirection === 'asc' ? 'desc' : 'asc');
    } else {
      setsortcolumn(column);
      setsortdirection('asc');
    }
  };

  useeffect(() => {
    let filtered = records;
    if (filterterm) {
      filtered = records.filter(record =>
        record.name.toLowerCase().includes(filterterm)
      );
    }

    if (sortcolumn) {
      filtered.sort((a, b) => {
        let valuea = a[sortcolumn];
        let valueb = b[sortcolumn];

        if (typeof valuea === 'number' && typeof valueb === 'number') {
          return sortdirection === 'asc' ? valuea - valueb : valueb - valuea;
        } else {
          return sortdirection === 'asc'
            ? valuea.localecompare(valueb)
            : valueb.localecompare(valuea);
        }
      });
    }

    setsorteddata(filtered);
  }, [filterterm, sortcolumn, sortdirection]);

  return (
    <div>
      <input
        type="text"
        placeholder="filter by name"
        value={filterterm}
        onChange={handlefilterchange}
      />
      <table>
        <thead>
          <tr>
            <th onClick={() => handlesort('id')}>id</th>
            <th onClick={() => handlesort('name')}>name</th>
            <th onClick={() => handlesort('age')}>age</th>
          </tr>
